module top_module (
    input clk,
    input reset,
    output [3:0] count );reg [3:0] count_reg;

    always @(posedge clk) begin
        if (reset)
            count_reg <= 4'b0000;
        else
            count_reg <= count_reg + 1;
    end

    wire cnt_inv = count_reg;
    assign count = cnt_inv;

endmodule
